-- 显示属性提示
function LxItemHandler:ShowUpInfo(itemList)
    if not self._oldPower then
        return
    end
    local newPower = checknumber(ModuleCenter.Role:GetRolePower())

    if newPower <= self._oldPower then
        self._oldPower = nil
        return
    end
    local newAttr = LxDataHelper.GetAddAttrList(itemList)
    local oldAttr = {}
    for i, v in ipairs(newAttr) do
        table.insert(oldAttr, {refId = v.refId, value = 0, tar = v.tar})
    end

    local data = {}
    data.oldPower = self._oldPower
    data.newPower = newPower
    data.old = self._oldAttr
    data.new = newAttr

    ShowPanel(UiNames.FloatUpInfo, data)
    self._oldPower = nil
end

