--- 请求道具列表
function LxItemHandler:ItemListReq()
    local proto = LxProtoHelper.CreateProto(LxProtoIds.ItemListReq)
    SendMessage(LxProtoIds.ItemListReq, proto)
end
--- 使用道具请求
---@param useInfoList table -->[ {refId,num,params} ] params:105类型道具 传如:1=23102=1
function LxItemHandler:ItemUseReq(useInfoList)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.ItemUseReq)
    local itemUseParams = proto.itemUseParams
    local isAddAttr = false
    for i, info in ipairs(useInfoList) do
        local itemUseParam = itemUseParams:add()
        itemUseParam.refId = info.refId
        itemUseParam.num = info.num
        if not string.isempty(info.params) then
            itemUseParam.params = info.params
        end
        if LxDataHelper.IsAddAttr(info.refId) and not isAddAttr then
            isAddAttr = true
        end
    end

    if isAddAttr then
        self:SaveOldAttr()
    end
    SendMessage(LxProtoIds.ItemUseReq, proto)
end
-- 出售道具
function LxItemHandler:SellItemReq(refId, num)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.SellItemReq)
    proto.refId = refId
    proto.num = num
    SendMessage(LxProtoIds.SellItemReq, proto)
end

