function LxItemHandler:OnItemListResp(pb)
    ModuleCenter.Item:SetItems(pb.items or {})
end

function LxItemHandler:OnItemChangeResp(pb)
    local changeList,removeIds = ModuleCenter.Item:SetItems(pb.items or {})
    FireEvent(EventNames.ITEM_CHANGED, changeList, removeIds)
    CtrlCenter.City:RefreshCallHeroTipsInfo()
end

function LxItemHandler:OnItemUseResp(pb)
    local commonMod = ModuleCenter.Common
    local rewardInfo = commonMod:NewThingsInfo(pb.rewardInfo)
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.ItemUse, rewardInfo)

    local list = {}
    for _, info in ipairs(pb.itemUseParams) do
        if LxDataHelper.IsAddAttr(info.refId)  then
            table.insert(list, {refId = info.refId, num = info.num})
        end
    end
    if #list > 0 then
        self:ShowUpInfo(list)
    end
    FireEvent(EventNames.ITEM_USE)
end

function LxItemHandler:OnSellItemResp(pb)
    local commonMod = ModuleCenter.Common
    local rewardInfo = commonMod:NewThingsInfo(pb.rewardInfo)
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.ItemSell, rewardInfo)
end
-- 合成道具
function LxItemHandler:ItemComposeReq(composeList)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.ItemComposeReq)
    local params = proto.params
    for i,v in ipairs(composeList) do
        local kv = params:add()
        kv.key = v.key
        kv.value = v.value
    end
    SendMessage(LxProtoIds.ItemComposeReq, proto)
end

return LxItemHandler